with seed_persons (code, name, tagline, avatar_url, description, is_active, era_codes) as (
  values
    ('jesus', '예수님', null, 'assets/avatars/jesus.png', '예수님은 하나님의 아들로, 사람들에게 하나님 나라를 가르치고 병든 자를 고치셨다. 십자가와 부활로 구원의 길을 여신 분이다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('paul', '바울', null, 'assets/avatars/paul.png', '바울은 예수님을 만난 뒤 복음을 널리 전한 사도다. 여러 도시를 다니며 교회를 세우고 서신을 남겼다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('john', '요한', null, 'assets/avatars/john.png', '요한은 예수님의 열두 제자 중 한 사람이다. 예수님의 사랑을 깊이 전했고 요한복음 전승과도 연결된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('god', '하나님', null, 'assets/avatars/god.png', '하나님은 세상을 창조하시고 역사를 주관하시는 분이다. 성경의 모든 이야기는 하나님의 뜻과 구원 계획 안에서 이어진다.', true, ARRAY['era_primeval']::text[]),
    ('peter', '베드로', null, 'assets/avatars/peter.png', '베드로는 예수님의 열두 제자 중 대표적인 인물로, 원래 갈릴리의 어부였다. 복음서와 초대교회에서 담대하게 복음을 전한다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('moses', '모세', null, 'assets/avatars/moses.png', '모세는 이스라엘 백성을 이집트에서 이끌어 낸 출애굽의 지도자다. 시내산에서 율법을 받아 백성에게 전했다.', true, ARRAY['era_exodus']::text[]),
    ('jacob', '야곱', null, 'assets/avatars/jacob.png', '야곱은 이삭과 리브가의 아들로, 이스라엘 열두 지파의 조상이 되었다. 하나님과 씨름한 뒤 이스라엘이라는 이름을 받았다.', true, ARRAY['era_patriarch']::text[]),
    ('philip', '빌립', null, 'assets/avatars/philip.png', '빌립은 예수님의 제자 중 한 사람으로, 사람들을 예수님께 인도하는 모습으로 자주 등장한다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('andrew', '안드레', null, 'assets/avatars/andrew.png', '안드레는 베드로의 형제이자 예수님의 제자였다. 먼저 예수님을 따르고 다른 사람을 데려오는 역할로 기억된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('abraham', '아브라함', null, 'assets/avatars/abraham.png', '아브라함은 하나님의 부르심을 따라 고향을 떠난 믿음의 조상이다. 하나님은 그에게 자손과 땅에 대한 약속을 주셨다.', true, ARRAY['era_patriarch']::text[]),
    ('bartholomew', '바돌로매', null, 'assets/avatars/bartholomew.png', '바돌로매는 예수님의 열두 제자 중 한 사람이다. 전승에서는 나다나엘과 연결해 보기도 한다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('james_alphaeus', '야고보(알패오의 아들)', null, 'assets/avatars/james_alphaeus.png', '야고보(알패오의 아들)는 예수님의 열두 제자 중 한 사람이다. 복음서에서는 조용하지만 끝까지 함께한 제자로 전해진다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('james_zebedee', '야고보(세베대의 아들)', null, 'assets/avatars/james_zebedee.png', '야고보(세베대의 아들)는 요한의 형제이자 예수님의 제자였다. 열정적인 제자 가운데 하나로 기억된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('matthew', '마태', null, 'assets/avatars/matthew.png', '마태는 세리 출신으로 예수님의 부르심을 받고 제자가 되었다. 전승에서는 마태복음과 연결된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('simon_zealot', '시몬(셀롯)', null, 'assets/avatars/simon_zealot.png', '시몬(셀롯)은 예수님의 열두 제자 중 한 사람이다. 이름에서 열심당과 관련된 배경을 짐작하게 한다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('thaddaeus', '다대오(유다)', null, 'assets/avatars/thaddaeus.png', '다대오(유다)는 예수님의 열두 제자 중 한 사람이다. 복음서에서는 유다라는 이름으로도 불린다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('thomas', '도마', null, 'assets/avatars/thomas.png', '도마는 예수님의 제자로, 부활하신 예수님을 확인하려 했던 모습으로 잘 알려져 있다. 이후에는 분명한 믿음의 고백을 남긴다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('david', '다윗', null, 'assets/avatars/david.png', '다윗은 목동 출신으로 골리앗을 물리치고 이스라엘의 왕이 되었다. 시편과 깊이 연결되는 인물이다.', true, ARRAY['era_monarchy']::text[]),
    ('judas', '유다', null, 'assets/avatars/judas.png', '가룟 유다는 예수님의 열두 제자 중 한 사람이었지만, 예수님을 넘겨준 인물로 기억된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('joseph', '요셉', null, 'assets/avatars/joseph.png', '요셉은 야곱의 아들로, 형들에게 팔려 이집트에 갔지만 하나님의 인도 속에 총리가 되었다. 기근 속에서 가족을 살린 인물이다.', true, ARRAY['era_patriarch']::text[]),
    ('pharaoh', '바로', null, 'assets/avatars/pharaoh.png', '바로는 출애굽 이야기에서 이스라엘 백성을 억압한 이집트의 왕이다. 완고한 마음으로 하나님의 경고를 거듭 거부했다.', true, ARRAY['era_exodus']::text[]),
    ('samuel', '사무엘', null, 'assets/avatars/samuel.png', '사무엘은 사사이자 예언자로, 이스라엘이 왕정으로 넘어가는 중요한 시기를 이끈 인물이다.', true, ARRAY['era_monarchy']::text[]),
    ('saul', '사울', null, 'assets/avatars/saul.png', '사울은 이스라엘의 첫 번째 왕이다. 처음에는 겸손했지만 점차 하나님께 불순종하며 비극적인 끝을 맞았다.', true, ARRAY['era_monarchy']::text[]),
    ('barnabas', '바나바', null, 'assets/avatars/barnabas.png', '바나바는 초대교회에서 바울을 도와 선교에 함께한 동역자다. 사람을 격려하고 세우는 인물로 알려져 있다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('sarah', '사라', null, 'assets/avatars/sarah.png', '사라는 아브라함의 아내이자 이삭의 어머니이다. 늦은 나이에 약속의 아들을 낳았다.', true, ARRAY['era_patriarch']::text[]),
    ('mary', '마리아', null, 'assets/avatars/mary.png', '마리아는 예수님의 어머니로, 하나님의 부르심에 믿음으로 응답한 인물이다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('daniel', '다니엘', null, 'assets/avatars/daniel.png', '다니엘은 바벨론 포로 시기에 하나님께 끝까지 충성한 인물이다. 지혜와 믿음으로 왕들 앞에서도 흔들리지 않았다.', true, ARRAY['era_exile_return']::text[]),
    ('elijah', '엘리야', null, 'assets/avatars/elijah.png', '엘리야는 북이스라엘에서 활동한 예언자다. 갈멜산 대결과 하나님의 불 응답 이야기로 잘 알려져 있다.', true, ARRAY['era_monarchy']::text[]),
    ('esther', '에스더', null, 'assets/avatars/esther.png', '에스더는 페르시아 제국의 왕후가 되어 자기 민족을 위기에서 구한 인물이다. 지혜와 용기로 중요한 때를 붙든다.', true, ARRAY['era_exile_return']::text[]),
    ('isaac', '이삭', null, 'assets/avatars/isaac.png', '이삭은 아브라함과 사라에게 약속으로 주어진 아들이다. 야곱과 에서의 아버지이기도 하다.', true, ARRAY['era_patriarch']::text[]),
    ('joshua', '여호수아', null, 'assets/avatars/joshua.png', '여호수아는 모세의 뒤를 이어 이스라엘 백성을 가나안으로 이끈 지도자다. 믿음과 순종으로 약속의 땅 정복을 이끌었다.', true, ARRAY['era_judges']::text[]),
    ('mordecai', '모르드개', null, 'assets/avatars/mordecai.png', '모르드개는 에스더를 돌보며 유다 민족을 지키기 위해 힘쓴 인물이다. 에스더 이야기에서 중요한 조언자 역할을 한다.', true, ARRAY['era_exile_return']::text[]),
    ('silas', '실라', null, 'assets/avatars/silas.png', '실라는 바울과 함께 여러 지역을 다니며 복음을 전한 초대교회 지도자다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('timothy', '디모데', null, 'assets/avatars/timothy.png', '디모데는 바울의 젊은 동역자로, 여러 교회를 돌보며 신앙을 이어 간 인물이다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('aaron', '아론', null, 'assets/avatars/aaron.png', '아론은 모세의 형으로, 출애굽 과정에서 모세를 도왔다. 이스라엘의 첫 대제사장으로도 중요한 위치를 차지한다.', true, ARRAY['era_exodus']::text[]),
    ('adam', '아담', null, 'assets/avatars/adam.png', '아담은 하나님이 지으신 첫 사람이다. 하와와 함께 에덴동산 이야기의 중심에 선다.', true, ARRAY['era_primeval']::text[]),
    ('esau', '에서', null, 'assets/avatars/esau.png', '에서는 이삭의 아들이자 야곱의 형이다. 장자권을 가볍게 여긴 이야기로 잘 알려져 있다.', true, ARRAY['era_patriarch']::text[]),
    ('eve', '하와', null, 'assets/avatars/eve.png', '하와는 하나님이 아담과 함께 살도록 주신 첫 여자이다. 에덴동산에서 뱀의 유혹을 받은 인물로 등장한다.', true, ARRAY['era_primeval']::text[]),
    ('james', '야고보', null, 'assets/avatars/james.png', '야고보는 예수님의 제자 가운데 한 사람으로, 초대교회에서도 중요한 인물로 전해진다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('joseph_nazareth', '요셉(예수의 양아버지)', null, 'assets/avatars/joseph_nazareth.png', '요셉(예수의 양아버지)는 성경에 등장하는 인물로, 대표적으로 ''예수 탄생과 목자들'' 이야기와 연결된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('laban', '라반', null, 'assets/avatars/laban.png', '라반은 리브가의 오빠이자 야곱의 외삼촌이다. 야곱이 그의 집에서 오랫동안 일하며 레아와 라헬을 아내로 맞게 된다.', true, ARRAY['era_patriarch']::text[]),
    ('nehemiah', '느헤미야', null, 'assets/avatars/nehemiah.png', '느헤미야는 페르시아 궁정에서 일하다가 예루살렘 성벽 재건을 이끈 지도자다.', true, ARRAY['era_exile_return']::text[]),
    ('rachel', '라헬', null, 'assets/avatars/rachel.png', '라헬은 야곱이 사랑한 아내이며 요셉과 베냐민의 어머니이다.', true, ARRAY['era_patriarch']::text[]),
    ('ruth', '룻', null, 'assets/avatars/ruth.png', '룻은 모압 여인이었지만 나오미를 따라 이스라엘로 와 믿음의 길을 택했다. 보아스와의 결혼을 통해 다윗의 계보에 들어간다.', true, ARRAY['era_judges']::text[]),
    ('solomon', '솔로몬', null, 'assets/avatars/solomon.png', '솔로몬은 다윗의 아들로, 지혜로 유명한 이스라엘의 왕이다. 예루살렘 성전을 세운 왕으로도 알려져 있다.', true, ARRAY['era_monarchy']::text[]),
    ('ananias', '아나니아', null, 'assets/avatars/ananias.png', '아나니아는 초대교회에서 헌금 문제로 거짓말한 인물이다. 아내 삽비라와 함께 경고의 사례로 등장한다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('benjamin', '베냐민', null, 'assets/avatars/benjamin.png', '베냐민은 야곱과 라헬 사이에서 태어난 막내아들이다. 요셉 이야기에서 형제들의 변화와 함께 중요한 역할을 한다.', true, ARRAY['era_patriarch']::text[]),
    ('boaz', '보아스', null, 'assets/avatars/boaz.png', '보아스는 룻을 선대하고 보호한 친족 기업 무를 자이다. 룻과 결혼해 다윗 가문의 조상이 된다.', true, ARRAY['era_judges']::text[]),
    ('elisha', '엘리사', null, 'assets/avatars/elisha.png', '엘리사는 엘리야의 뒤를 이어 활동한 예언자다. 여러 기적 이야기로 잘 알려져 있다.', true, ARRAY['era_monarchy']::text[]),
    ('elizabeth', '엘리사벳', null, 'assets/avatars/elizabeth.png', '엘리사벳은 세례 요한의 어머니이며, 제사장 사가랴의 아내이다. 늙은 나이에 아들을 낳는 은혜를 받았다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('ezra', '에스라', null, 'assets/avatars/ezra.png', '에스라는 포로 귀환 이후 백성에게 율법을 가르치고 공동체를 바로 세운 학자 겸 제사장이다.', true, ARRAY['era_exile_return']::text[]),
    ('gabriel', '가브리엘', null, 'assets/avatars/gabriel.png', '가브리엘은 하나님의 소식을 전하는 천사로, 세례 요한과 예수님의 탄생 예고 장면에 등장한다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('gideon', '기드온', null, 'assets/avatars/gideon.png', '기드온은 미디안의 압제 아래 있던 이스라엘을 구하도록 부름받은 사사이다. 작은 수의 군사로 하나님의 구원을 경험했다.', true, ARRAY['era_judges']::text[]),
    ('hagar', '하갈', null, 'assets/avatars/hagar.png', '하갈은 사라의 여종이었고 아브라함을 통해 이스마엘을 낳았다. 광야에서 하나님이 자신을 돌보심을 경험한다.', true, ARRAY['era_patriarch']::text[]),
    ('haman', '하만', null, 'assets/avatars/haman.png', '하만은 페르시아 제국에서 유다인을 없애려 한 악한 고관이다. 에스더 이야기의 주요 대적자로 나온다.', true, ARRAY['era_exile_return']::text[]),
    ('hezekiah', '히스기야', null, 'assets/avatars/hezekiah.png', '히스기야는 유다의 왕으로, 하나님을 의지하며 종교 개혁을 이루려 했던 인물이다.', true, ARRAY['era_monarchy']::text[]),
    ('isaiah', '이사야', null, 'assets/avatars/isaiah.png', '이사야는 유다에서 활동한 예언자로, 심판과 회복 그리고 메시아에 대한 소망을 선포했다.', true, ARRAY['era_monarchy']::text[]),
    ('judah', '유다', null, 'assets/avatars/judah.png', '유다는 야곱의 아들 가운데 한 사람으로, 훗날 메시아 계보와 연결되는 지파의 조상이 되었다.', true, ARRAY['era_patriarch']::text[]),
    ('leah', '레아', null, 'assets/avatars/leah.png', '레아는 라반의 딸이자 야곱의 아내이다. 여러 아들의 어머니가 되어 이스라엘 가계에서 중요한 위치를 차지한다.', true, ARRAY['era_patriarch']::text[]),
    ('lot', '롯', null, 'assets/avatars/lot.png', '롯은 아브라함의 조카로, 소돔과 고모라 이야기에서 잘 알려진다.', true, ARRAY['era_patriarch']::text[]),
    ('matthias', '맛디아', null, 'assets/avatars/matthias.png', '맛디아는 가룟 유다 대신 사도의 자리를 잇도록 뽑힌 인물이다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('naomi', '나오미', null, 'assets/avatars/naomi.png', '나오미는 룻의 시어머니로, 깊은 상실 속에서도 하나님의 돌보심을 다시 경험한다.', true, ARRAY['era_judges']::text[]),
    ('noah', '노아', null, 'assets/avatars/noah.png', '노아는 세상이 악해졌을 때 하나님께 순종해 방주를 지은 인물이다. 홍수 심판 가운데 가족과 함께 보존되었다.', true, ARRAY['era_primeval']::text[]),
    ('rebekah', '리브가', null, 'assets/avatars/rebekah.png', '리브가는 이삭의 아내이자 야곱과 에서의 어머니이다. 족장 이야기에서 중요한 선택의 순간들과 함께 등장한다.', true, ARRAY['era_patriarch']::text[]),
    ('abel', '아벨', null, 'assets/avatars/abel.png', '아벨은 성경에 등장하는 인물로, 대표적으로 ''가인과 아벨: 들판의 비극'' 이야기와 연결된다.', false, ARRAY['era_primeval']::text[]),
    ('abimelech', '아비멜렉', null, 'assets/avatars/abimelech.png', '아비멜렉은 기드온의 아들로, 스스로 왕이 되려 했던 인물이다. 권력을 향한 욕심이 결국 비극으로 이어졌다.', false, ARRAY['era_judges']::text[]),
    ('achan', '아간', null, 'assets/avatars/achan.png', '아간은 성경에 등장하는 인물로, 대표적으로 ''아간: 감춘 것이 드러나다'' 이야기와 연결된다.', false, ARRAY['era_judges']::text[]),
    ('agrippa', '아그립바', null, 'assets/avatars/agrippa.png', '아그립바는 성경에 등장하는 인물로, 대표적으로 ''로마행(2): 가이사랴 재판과 상소'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('aquila', '아굴라', null, 'assets/avatars/aquila.png', '아굴라는 성경에 등장하는 인물로, 대표적으로 ''2차 선교(6): 고린도—정착과 견딤'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('asher', '아셀', null, 'assets/avatars/asher.png', '아셀은 야곱의 아들 가운데 한 사람이다. 훗날 이스라엘 열두 지파 가운데 하나의 조상이 되었다.', false, ARRAY['era_patriarch']::text[]),
    ('cain', '가인', null, 'assets/avatars/cain.png', '가인은 성경에 등장하는 인물로, 대표적으로 ''가인과 아벨: 들판의 비극'' 이야기와 연결된다.', false, ARRAY['era_primeval']::text[]),
    ('cornelius', '고넬료', null, 'assets/avatars/cornelius.png', '고넬료는 성경에 등장하는 인물로, 대표적으로 ''고넬료: 이방인에게도'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('delilah', '들릴라', null, 'assets/avatars/delilah.png', '들릴라는 성경에 등장하는 인물로, 대표적으로 ''삼손: 힘의 비밀과 마지막 기도'' 이야기와 연결된다.', false, ARRAY['era_judges']::text[]),
    ('ezekiel', '에스겔', null, 'assets/avatars/ezekiel.png', '에스겔은 바벨론 포로 시기에 활동한 예언자다. 상징 행동과 환상을 통해 하나님의 말씀을 전했다.', false, ARRAY['era_exile_return']::text[]),
    ('festus', '베스도', null, 'assets/avatars/festus.png', '베스도는 성경에 등장하는 인물로, 대표적으로 ''로마행(2): 가이사랴 재판과 상소'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('gad', '갓', null, 'assets/avatars/gad.png', '갓은 야곱의 아들 가운데 한 사람이다. 훗날 이스라엘 열두 지파 가운데 하나의 조상이 되었다.', false, ARRAY['era_patriarch']::text[]),
    ('goliath', '골리앗', null, 'assets/avatars/goliath.png', '골리앗은 성경에 등장하는 인물로, 대표적으로 ''다윗과 골리앗: 돌 하나'' 이야기와 연결된다.', false, ARRAY['era_monarchy']::text[]),
    ('herod', '헤롯', null, 'assets/avatars/herod.png', '헤롯은 성경에 등장하는 인물로, 대표적으로 ''동방박사와 피신'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('ishmael', '이스마엘', null, 'assets/avatars/ishmael.png', '이스마엘은 아브라함과 하갈 사이에서 태어난 아들이다. 광야로 나가게 되지만 하나님이 그와 그의 어머니를 돌보셨다.', false, ARRAY['era_patriarch']::text[]),
    ('issachar', '잇사갈', null, 'assets/avatars/issachar.png', '잇사갈은 야곱의 아들 가운데 한 사람이다. 훗날 이스라엘 열두 지파 가운데 하나의 조상이 되었다.', false, ARRAY['era_patriarch']::text[]),
    ('jairus', '야이로', null, 'assets/avatars/jairus.png', '야이로는 성경에 등장하는 인물로, 대표적으로 ''야이로의 딸과 혈루증 여인'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('jesse', '이새', null, 'assets/avatars/jesse.png', '이새는 성경에 등장하는 인물로, 대표적으로 ''다윗의 기름부음: 새로운 선택'' 이야기와 연결된다.', false, ARRAY['era_monarchy']::text[]),
    ('john_mark', '마가 요한', null, 'assets/avatars/john_mark.png', '마가 요한은 성경에 등장하는 인물로, 대표적으로 ''1차 선교(1): 구브로 살라미–바보'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('john_the_baptist', '세례 요한', null, 'assets/avatars/john_the_baptist.png', '세례 요한은 성경에 등장하는 인물로, 대표적으로 ''예수의 세례'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('jonathan', '요나단', null, 'assets/avatars/jonathan.png', '요나단은 성경에 등장하는 인물로, 대표적으로 ''사울의 시기: 다윗의 도망 시작'' 이야기와 연결된다.', false, ARRAY['era_judges']::text[]),
    ('josiah', '요시야', null, 'assets/avatars/josiah.png', '요시야는 성경에 등장하는 인물로, 대표적으로 ''요시야의 개혁: 율법책을 찾다'' 이야기와 연결된다.', false, ARRAY['era_monarchy']::text[]),
    ('lazarus', '나사로', null, 'assets/avatars/lazarus.png', '나사로는 성경에 등장하는 인물로, 대표적으로 ''나사로의 부활'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('levi', '레위', null, 'assets/avatars/levi.png', '레위는 야곱의 아들 가운데 한 사람이다. 훗날 레위 지파는 성막과 성전 섬김을 맡게 된다.', false, ARRAY['era_patriarch']::text[]),
    ('lydia', '루디아', null, 'assets/avatars/lydia.png', '루디아는 성경에 등장하는 인물로, 대표적으로 ''2차 선교(2): 빌립보—루디아와 감옥의 찬양'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('martha', '마르다', null, 'assets/avatars/martha.png', '마르다는 성경에 등장하는 인물로, 대표적으로 ''나사로의 부활'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('mary_magdalene', '막달라 마리아', null, 'assets/avatars/mary_magdalene.png', '막달라 마리아는 성경에 등장하는 인물로, 대표적으로 ''부활과 승천: 새 시작'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('naaman', '나아만', null, 'assets/avatars/naaman.png', '나아만은 성경에 등장하는 인물로, 대표적으로 ''나아만: 요단의 일곱 번'' 이야기와 연결된다.', false, ARRAY['era_monarchy']::text[]),
    ('naphtali', '납달리', null, 'assets/avatars/naphtali.png', '납달리는 야곱의 아들 가운데 한 사람이다. 훗날 이스라엘 열두 지파 가운데 하나의 조상이 되었다.', false, ARRAY['era_patriarch']::text[]),
    ('nathan', '나단', null, 'assets/avatars/nathan.png', '나단은 다윗 시대의 예언자로, 다윗의 죄를 책망하고 하나님의 약속을 전한 인물이다.', false, ARRAY['era_monarchy']::text[]),
    ('pilate', '빌라도', null, 'assets/avatars/pilate.png', '빌라도는 성경에 등장하는 인물로, 대표적으로 ''재판: 빌라도 앞'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('potiphar', '보디발', null, 'assets/avatars/potiphar.png', '보디발은 성경에 등장하는 인물로, 대표적으로 ''보디발의 집: 성실과 누명'' 이야기와 연결된다.', false, ARRAY['era_patriarch']::text[]),
    ('reuben', '르우벤', null, 'assets/avatars/reuben.png', '르우벤은 야곱의 맏아들이다. 장자의 위치를 가졌지만 그 책임을 끝까지 지키지는 못했다.', false, ARRAY['era_patriarch']::text[]),
    ('samson', '삼손', null, 'assets/avatars/samson.png', '삼손은 성경에 등장하는 인물로, 대표적으로 ''삼손: 힘의 비밀과 마지막 기도'' 이야기와 연결된다.', false, ARRAY['era_judges']::text[]),
    ('sapphira', '삽비라', null, 'assets/avatars/sapphira.png', '삽비라는 성경에 등장하는 인물로, 대표적으로 ''아나니아와 삽비라'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('simeon', '시므온', null, 'assets/avatars/simeon.png', '시므온은 야곱의 아들 가운데 한 사람이다. 레위와 함께 디나 사건에서 강한 분노를 드러낸 인물로 나온다.', false, ARRAY['era_patriarch']::text[]),
    ('stephen', '스데반', null, 'assets/avatars/stephen.png', '스데반은 성경에 등장하는 인물로, 대표적으로 ''일곱 집사와 스데반 순교'' 이야기와 연결된다.', false, ARRAY['era_nt_apostolic']::text[]),
    ('zebulun', '스불론', null, 'assets/avatars/zebulun.png', '스불론은 야곱의 아들 가운데 한 사람이다. 훗날 이스라엘 열두 지파 가운데 하나의 조상이 되었다.', false, ARRAY['era_patriarch']::text[]),
    ('zechariah', '사가랴', null, 'assets/avatars/zechariah.png', '사가랴는 성경에 등장하는 인물로, 대표적으로 ''세례 요한의 탄생 예고'' 이야기와 연결된다.', false, ARRAY['era_nt_public_ministry']::text[]),
    ('zedekiah', '시드기야', null, 'assets/avatars/zedekiah.png', '시드기야는 성경에 등장하는 인물로, 대표적으로 ''예루살렘 포위: 왕의 몰락'' 이야기와 연결된다.', false, ARRAY['era_monarchy']::text[])
)
insert into characters (code, name, tagline, avatar_url, description, is_active, era_codes)
select code, name, tagline, avatar_url, description, is_active, era_codes from seed_persons
on conflict (code) do update set
  name = excluded.name,
  tagline = coalesce(excluded.tagline, characters.tagline),
  avatar_url = excluded.avatar_url,
  description = coalesce(excluded.description, characters.description),
  era_codes = excluded.era_codes
;

commit;
